import { useState, useCallback } from 'react'
import { Modal, Stack, Select, TextInput, Textarea, Alert, Group } from '@mantine/core'
import { Button } from '@/components/ui/button'
import { graphql } from 'gql.tada'
import { useMutation } from '@/lib/graphql'
import { useAuthStore } from '@/stores/authStore'

interface FeedbackModalProps {
  opened: boolean
  onClose: () => void
}

const CATEGORY_OPTIONS = [
  { value: 'BUG', label: 'Bug Report' },
  { value: 'FEATURE', label: 'Feature Request' },
  { value: 'GENERAL', label: 'General Feedback' },
]

const SubmitFeedbackMutation = graphql(`
  mutation SubmitFeedback($input: SubmitFeedbackInput!) {
    submitFeedback(input: $input) {
      id
      success
    }
  }
`)

type FeedbackState = { type: 'success' | 'error'; message: string } | null

export function FeedbackModal({ opened, onClose }: FeedbackModalProps) {
  const session = useAuthStore((s) => s.session)

  const [category, setCategory] = useState<string | null>(null)
  const [subject, setSubject] = useState('')
  const [description, setDescription] = useState('')
  const [email, setEmail] = useState('')
  const [submitting, setSubmitting] = useState(false)
  const [feedback, setFeedback] = useState<FeedbackState>(null)
  const [errors, setErrors] = useState<Record<string, string>>({})

  const [, executeMutation] = useMutation(SubmitFeedbackMutation)

  const resetForm = useCallback(() => {
    setCategory(null)
    setSubject('')
    setDescription('')
    setEmail('')
    setFeedback(null)
    setErrors({})
  }, [])

  const validate = useCallback((): boolean => {
    const newErrors: Record<string, string> = {}
    if (!category) newErrors.category = 'Category is required'
    if (!subject.trim()) newErrors.subject = 'Subject is required'
    if (!description.trim()) newErrors.description = 'Description is required'
    setErrors(newErrors)
    return Object.keys(newErrors).length === 0
  }, [category, subject, description])

  const handleSubmit = useCallback(async () => {
    if (!validate()) return

    setSubmitting(true)
    setFeedback(null)

    const result = await executeMutation({
      input: {
        category: category!,
        subject: subject.trim(),
        description: description.trim(),
        email: session ? undefined : email.trim() || undefined,
        userAgent: navigator.userAgent,
        pageUrl: window.location.href,
      },
    })

    setSubmitting(false)

    if (result.error) {
      setFeedback({ type: 'error', message: 'Failed to send feedback. Please try again.' })
      return
    }

    setFeedback({ type: 'success', message: 'Thank you! Your feedback has been submitted.' })
    setTimeout(() => {
      resetForm()
      onClose()
    }, 1500)
  }, [validate, executeMutation, category, subject, description, session, email, resetForm, onClose])

  const handleClose = useCallback(() => {
    resetForm()
    onClose()
  }, [resetForm, onClose])

  return (
    <Modal opened={opened} onClose={handleClose} title="Send Feedback" size="md">
      <Stack gap="md">
        <Select
          label="Category"
          placeholder="What kind of feedback?"
          required
          data={CATEGORY_OPTIONS}
          value={category}
          onChange={setCategory}
          error={errors.category}
        />

        <TextInput
          label="Subject"
          placeholder="Brief summary"
          required
          maxLength={200}
          value={subject}
          onChange={(e) => setSubject(e.currentTarget.value)}
          error={errors.subject}
        />

        <Textarea
          label="Description"
          placeholder="Tell us more..."
          required
          maxLength={5000}
          minRows={4}
          value={description}
          onChange={(e) => setDescription(e.currentTarget.value)}
          error={errors.description}
        />

        {!session && (
          <TextInput
            label="Email"
            placeholder="your@email.com"
            description="Optional — so we can follow up"
            value={email}
            onChange={(e) => setEmail(e.currentTarget.value)}
          />
        )}

        {feedback && (
          <Alert color={feedback.type === 'success' ? 'green' : 'red'} variant="light">
            {feedback.message}
          </Alert>
        )}

        <Group justify="flex-end">
          <Button variant="outline" onClick={handleClose}>
            Cancel
          </Button>
          <Button
            variant="accent"
            onClick={() => void handleSubmit()}
            disabled={submitting}
          >
            {submitting ? 'Sending...' : 'Send Feedback'}
          </Button>
        </Group>
      </Stack>
    </Modal>
  )
}

import { describe, it, expect, vi } from 'vitest'
import { screen } from '@testing-library/react'
import userEvent from '@testing-library/user-event'
import { renderWithMantine } from '@/test/render'
import { FeedbackButton } from './FeedbackButton'

vi.mock('urql', async () => {
  const actual = await vi.importActual('urql')
  return {
    ...actual,
    useMutation: () => [{ fetching: false, error: null }, vi.fn()],
  }
})

describe('FeedbackButton', () => {
  it('renders the feedback button', () => {
    renderWithMantine(<FeedbackButton />)
    expect(screen.getByRole('button', { name: 'Send feedback' })).toBeInTheDocument()
  })

  it('opens the modal when clicked', async () => {
    const user = userEvent.setup()
    renderWithMantine(<FeedbackButton />)

    await user.click(screen.getByRole('button', { name: 'Send feedback' }))

    expect(screen.getByText('Send Feedback')).toBeInTheDocument()
  })
})

import { describe, it, expect, vi } from 'vitest'
import { screen } from '@testing-library/react'
import userEvent from '@testing-library/user-event'
import { renderWithMantine } from '@/test/render'
import { FeedbackModal } from './FeedbackModal'

vi.mock('urql', async () => {
  const actual = await vi.importActual('urql')
  return {
    ...actual,
    useMutation: () => [{ fetching: false, error: null }, vi.fn()],
  }
})

vi.mock('@/stores/authStore', () => ({
  useAuthStore: (selector: (s: { session: null }) => unknown) =>
    selector({ session: null }),
}))

describe('FeedbackModal', () => {
  it('renders form fields when opened', () => {
    renderWithMantine(<FeedbackModal opened={true} onClose={vi.fn()} />)

    expect(screen.getByText('Send Feedback')).toBeInTheDocument()
    expect(screen.getByLabelText(/category/i)).toBeInTheDocument()
    expect(screen.getByLabelText(/subject/i)).toBeInTheDocument()
    expect(screen.getByLabelText(/description/i)).toBeInTheDocument()
  })

  it('shows email field when user is not authenticated', () => {
    renderWithMantine(<FeedbackModal opened={true} onClose={vi.fn()} />)

    expect(screen.getByLabelText(/email/i)).toBeInTheDocument()
  })

  it('does not render when closed', () => {
    renderWithMantine(<FeedbackModal opened={false} onClose={vi.fn()} />)

    expect(screen.queryByText('Send Feedback')).not.toBeInTheDocument()
  })

  it('shows validation errors when submitting empty form', async () => {
    const user = userEvent.setup()
    renderWithMantine(<FeedbackModal opened={true} onClose={vi.fn()} />)

    await user.click(screen.getByRole('button', { name: 'Send Feedback' }))

    expect(screen.getByText('Category is required')).toBeInTheDocument()
    expect(screen.getByText('Subject is required')).toBeInTheDocument()
    expect(screen.getByText('Description is required')).toBeInTheDocument()
  })
})
